class Trie:
    def __init__(self):
        self.root = {
            '.': {}
        };

    def insert(self, s):
        node = self.root;
        for c in s:
            if c not in node:
                node[c] = {
                    '.': {}
                };
            node = node[c];
        node['.'] = True;
        return True;

    def search(self, s):
        node = self.root;
        for c in s:
            if c not in node:
                return False;
            node = node[c];
        return True;

