class Trie {
public:
    Trie() {
        root = {
            '.': {}
        };
    }

    bool insert(string s) {
        node = root;
        for (char c : s) {
            if (root.find(c) == root.end()) {
                root[c] = {
                    '.': {}
                };
            }
            node = node[c];
        }
        node['.'] = true;
        return true;
    }

    bool search(string s) {
        node = root;
        for (char c : s) {
            if (root.find(c) == root.end()) {
                return false;
            }
            node = node[c];
        }
        return true;
    }
private:
    unordered_map<char, unordered_map<char, unordered_map<char, bool> > > root;
};
